const VOCAB_KEY = "ssc-vocab-private-lite";

function decodeVocab() {
  const encoded = encodedVocab.join("");
  const binary = atob(encoded);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i) ^ VOCAB_KEY.charCodeAt(i % VOCAB_KEY.length);
  }
  return JSON.parse(new TextDecoder().decode(bytes));
}

const vocab = decodeVocab();

export default vocab;
